def collect(items: list[dict[str, Any]], key: str) -> set[str]:
    covered: set[str] = set()
    for item in items:
        covered.update(item.get(key, []))
    return covered


def missing(paths: set[str]) -> list[str]:
    return sorted(path for path in paths if not (ROOT / path).exists())


def main() -> int:
    data = json.loads(FIXTURE.read_text())
    items = data["coverageItems"]

    covered_okf = collect(items, "requiredOkf")
    covered_types = collect(items, "requiredTypes")
    covered_api = collect(items, "requiredApi")
    covered_validators = collect(items, "requiredValidators") | {"scripts/coverage/validate_okf_types_api_validator_coverage.py"}
    covered_fixtures = collect(items, "requiredFixtures") | {"fixtures/coverage/okf-types-api-validator-coverage.json"}

    failures: list[str] = []
    all_declared = covered_okf | covered_types | covered_api | covered_validators | covered_fixtures
    missing_files = missing(all_declared)
    if missing_files:
        failures.append(f"missing files: {missing_files}")

    expected = data["expected"]
    actual = {
        "coverageItemCount": len(items),
        "missingFiles": len(missing_files),
        "okfFilesCoveredAtLeastOnce": len(covered_okf & EXPECTED_OKF),
        "typeFilesCoveredAtLeastOnce": len(covered_types & EXPECTED_TYPES),
        "apiFilesCoveredAtLeastOnce": len(covered_api & EXPECTED_API),
        "validatorFilesCoveredAtLeastOnce": len(covered_validators & EXPECTED_VALIDATORS),
        "fixtureFilesCoveredAtLeastOnce": len(covered_fixtures & EXPECTED_FIXTURES),
        "noWrite": True,
        "businessWrites": 0,
        "externalApiWrites": 0,
    }

    for key, expected_value in expected.items():
        if actual.get(key) != expected_value:
            failures.append(f"{key}: expected={expected_value!r} actual={actual.get(key)!r}")

    if covered_okf != EXPECTED_OKF:
        failures.append(f"okf coverage mismatch missing={sorted(EXPECTED_OKF - covered_okf)} extra={sorted(covered_okf - EXPECTED_OKF)}")
    if covered_types != EXPECTED_TYPES:
        failures.append(
            f"type coverage mismatch missing={sorted(EXPECTED_TYPES - covered_types)} extra={sorted(covered_types - EXPECTED_TYPES)}"
        )
    if covered_api != EXPECTED_API:
        failures.append(f"api coverage mismatch missing={sorted(EXPECTED_API - covered_api)} extra={sorted(covered_api - EXPECTED_API)}")

    if failures:
        print("okf_types_api_validator_coverage=fail")
        for failure in failures:
            print(failure)
        return 1

    print(
        "okf_types_api_validator_coverage=pass "
        f"coverage_items={actual['coverageItemCount']} "
        f"okf_files={actual['okfFilesCoveredAtLeastOnce']} "
        f"type_files={actual['typeFilesCoveredAtLeastOnce']} "
        f"api_files={actual['apiFilesCoveredAtLeastOnce']} "
        f"validator_files={actual['validatorFilesCoveredAtLeastOnce']} "
        f"fixture_files={actual['fixtureFilesCoveredAtLeastOnce']} "
        "missing_files=0 no_write=covered business_writes=0 external_api_writes=0"
    )
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
